const input = $input.first().json;

// ========================================
// PARSEAR DADOS
// ========================================

let dados = input.secoes_json;

// Se vier como string JSON, parsear
if (typeof dados === 'string') {
  dados = JSON.parse(dados);
}

console.log('Dados parseados com sucesso!');
console.log('Empresa:', dados.dadosCabecalho.razaoSocial);
console.log('Período:', dados.dadosCabecalho.periodo);

// ========================================
// EXTRAIR DADOS DE CADA SEÇÃO
// ========================================

const cab = dados.dadosCabecalho;
const s1 = dados.dadosSecao1;
const s2 = dados.dadosSecao2;
const s3 = dados.dadosSecao3;
const s4 = dados.dadosSecao4;
const s5 = dados.dadosSecao5;
const s6 = dados.dadosSecao6;
const s7 = dados.dadosSecao7;
const s8 = dados.dadosSecao8;

// ========================================
// ✅ CORRIGIR SEÇÃO 8 - OBSERVAÇÃO
// ========================================

const anexo = s1.anexo || s8.detalhes?.anexo;
const atividade = (['I', 'II'].includes(anexo)) ? 'comércio' : 'prestação de serviços';

// Usar valores já formatados
const divergenciaFormatada = s2.divergencia?.valorFormatado || 'R$ 0,00';
const divergenciaPct = s2.divergencia?.porcentagem || '0%';
const divergenciaExiste = s2.divergencia?.valor > 0;

// ✅ OBSERVAÇÃO CORRIGIDA
const observacaoCorrigida = `A empresa ${cab.razaoSocial} é optante pelo Simples Nacional e atua no ramo de ${atividade}, enquadrada no Anexo ${anexo}. O extrato bancário (${s2.banco}) ${divergenciaExiste ? 'apresenta divergência de ' + divergenciaFormatada + ' (' + divergenciaPct + ')' : 'está em conformidade'} entre o movimento financeiro e a receita declarada. O DAS da competência ${cab.periodo} está pendente de pagamento.`;

console.log('✅ Observação corrigida:', observacaoCorrigida);

// ========================================
// VALIDAR SE DEVE MOSTRAR SEÇÃO 7
// ========================================

const ehComercio = ['I', 'II'].includes(anexo);
const mostrarSecao7 = !ehComercio && s7 !== null && s7?.temDadosSuficientes;

console.log('=== VALIDAÇÃO SEÇÃO 7 ===');
console.log('Anexo da empresa:', anexo);
console.log('É comércio (I ou II)?', ehComercio);
console.log('Seção 7 é null?', s7 === null);
console.log('Mostrar Seção 7?', mostrarSecao7);

// ========================================
// VALIDAR STATUS DOS DOCUMENTOS
// ========================================

const temVendasCartao = s2.movimento?.vendasCartao?.valor > 0;

if (s6 && s6.documentos) {
  s6.documentos = s6.documentos.map(doc => {
    if (doc.nome.toLowerCase().includes('cartão') || doc.nome.toLowerCase().includes('administradora')) {
      if (temVendasCartao) {
        console.log('✅ Corrigindo status do Extrato do Cartão: marcando como ANALISADO');
        return {
          ...doc,
          analisado: true,
          icone: '✓',
          cor: '#10b981'
        };
      }
    }
    return doc;
  });

  s6.resumo.analisados = s6.documentos.filter(d => d.analisado).length;
  s6.resumo.naoAnalisados = s6.documentos.filter(d => !d.analisado).length;
}

// ========================================
// GERAR HTML COMPLETO
// ========================================

